SELECT id, product_name, product_model_number, cloth_paper_type_id, compatibility_status, paper_type, notice_ids, created_at, updated_at FROM post_processing_leduvglitter
AND product_name = #{productName}
AND product_model_number = #{productModelNumber}
AND cloth_paper_type_id = #{clothPaperTypeId}
ORDER BY product_name, product_model_number, cloth_paper_type_id

SELECT id, product_name, product_model_number, cloth_paper_type_id, compatibility_status, paper_type, created_at, updated_at FROM post_processing_leduvglitter WHERE product_name = #{productName} AND cloth_paper_type_id = #{clothPaperTypeId}
AND ( (product_model_number = #{productModelNumber} AND product_model_number IS NOT NULL AND product_model_number != '') )
AND (product_model_number IS NULL OR product_model_number = '')
AND paper_type = #{paperType}
AND (paper_type IS NULL OR paper_type = '')
LIMIT 1

SELECT DISTINCT unnest(notice_ids)
FROM post_processing_leduvglitter
WHERE notice_ids IS NOT NULL
AND array_length(notice_ids, 1) > 0
AND compatibility_status IN ('V', '▷')

    AND cloth_paper_type_id = #{clothPaperTypeId}


    AND product_model_number = #{productModelNumber}


    AND product_name = #{productName}
